{
  "name": "Générateur de Rapport Académique",
  "description": "Une application pour générer des rapports académiques structurés en utilisant l'API Gemini, basée sur des instructions détaillées. L'application génère le rapport et permet de le télécharger au format .doc."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useCallback } from 'react';
import { generateReport } from './services/geminiService';
import { DEFAULT_PROMPT } from './constants';
import Header from './components/Header';
import PromptInput from './components/PromptInput';
import ReportOutput from './components/ReportOutput';

// Declare saveAs from FileSaver.js CDN script
declare const saveAs: (blob: Blob, filename: string) => void;

const App: React.FC = () => {
  const [prompt, setPrompt] = useState<string>(DEFAULT_PROMPT);
  const [reportContent, setReportContent] = useState<string>('');
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const handleGenerateReport = useCallback(async () => {
    if (!prompt.trim()) {
      setError('Le prompt ne peut pas être vide.');
      return;
    }
    setIsLoading(true);
    setError(null);
    setReportContent('');

    try {
      const result = await generateReport(prompt);
      setReportContent(result);
    } catch (e) {
      console.error(e);
      setError(e instanceof Error ? `Une erreur est survenue: ${e.message}` : 'Une erreur inconnue est survenue.');
    } finally {
      setIsLoading(false);
    }
  }, [prompt]);

  const handleDownload = useCallback(() => {
    const sourceEl = document.getElementById('html-source');
    if (!sourceEl) {
      console.error("L'élément source pour l'exportation est introuvable.");
      alert("Erreur lors de la préparation du téléchargement.");
      return;
    }

    const sourceHTML = sourceEl.innerHTML;
    const fullHtml = `
      <!DOCTYPE html>
      <html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:w="urn:schemas-microsoft-com:office:word" xmlns="http://www.w3.org/TR/REC-html40">
      <head>
        <meta charset="utf-8">
        <title>Rapport Académique</title>
        <style>
          @page {
            size: A4;
            margin: 2.5cm;
          }
          body { 
            font-family: 'Times New Roman', Times, serif; 
            font-size: 12pt;
            line-height: 1.5;
          }
          h1, h2, h3, h4 { 
            font-family: 'Arial', sans-serif; 
            color: #2F5496; /* Dark Blue */
            font-weight: bold;
          }
          h1 { font-size: 16pt; margin-top: 24pt; }
          h2 { font-size: 14pt; margin-top: 18pt; }
          h3 { font-size: 12pt; margin-top: 14pt; }
          p { margin-bottom: 12pt; }
          strong { font-weight: bold; }
          em { font-style: italic; }
          ul, ol { margin-left: 40px; margin-bottom: 12pt; }
          li { margin-bottom: 6pt; }
          table { border-collapse: collapse; width: 100%; margin-bottom: 12pt; }
          th, td { border: 1px solid #ccc; padding: 8px; text-align: left; }
          th { background-color: #f2f2f2; }
          pre { background-color: #f5f5f5; padding: 10px; border: 1px solid #ddd; font-family: 'Courier New', monospace; white-space: pre-wrap; }
        </style>
      </head>
      <body>${sourceHTML}</body>
      </html>
    `;

    try {
      const blob = new Blob([fullHtml], { type: 'application/msword;charset=utf-8' });
      saveAs(blob, 'rapport_academique.doc');
    } catch(e) {
      console.error("Erreur lors de la création du fichier .doc", e);
      alert("Impossible de télécharger le fichier. Assurez-vous que votre navigateur autorise les téléchargements.");
    }

  }, []);


  return (
    <div className="min-h-screen bg-gray-100 dark:bg-gray-900 text-gray-900 dark:text-gray-100 transition-colors duration-300">
      <Header />
      <main className="p-4 sm:p-6 lg:p-8">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 max-w-7xl mx-auto">
          <PromptInput
            prompt={prompt}
            setPrompt={setPrompt}
            onGenerate={handleGenerateReport}
            isLoading={isLoading}
          />
          <ReportOutput
            content={reportContent}
            isLoading={isLoading}
            error={error}
            onDownload={handleDownload}
          />
        </div>
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";

const SYSTEM_PROMPT = `
Vous êtes un générateur de rapports académiques de classe mondiale. Votre tâche est de générer un rapport académique complet, bien structuré et très détaillé en français, basé sur les instructions de l'utilisateur.
La sortie DOIT être un seul bloc de texte Markdown. N'incluez aucune autre explication ou préambule.
Utilisez les en-têtes Markdown (#, ##, ###) pour les titres et les sections.
Utilisez du texte en gras pour mettre l'accent.
Pour les espaces réservés aux captures d'écran, utilisez le format exact : **[Capture d’écran à insérer – Description]**
Assurez-vous que la langue est formelle, scientifique et pédagogique, adaptée à un jury universitaire (niveau Licence / Master / Cycle ingénieur).
Générez une table des matières complète.
N'incluez pas le code Python réel dans le rapport. Mentionnez plutôt qu'il est fourni dans un fichier séparé.
La sortie finale doit être un document Markdown unique et cohérent représentant l'ensemble du rapport, de la page de garde aux annexes.
`;

export const generateReport = async (prompt: string): Promise<string> => {
  if (!process.env.API_KEY) {
    throw new Error("La variable d'environnement API_KEY n'est pas définie.");
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const fullPrompt = `${SYSTEM_PROMPT}\n\nVoici les instructions de l'utilisateur :\n\n${prompt}`;

    const response = await ai.models.generateContent({
        model: "gemini-3-pro-preview",
        contents: fullPrompt,
    });

    if (!response.text) {
        throw new Error("La réponse de l'API est vide.");
    }

    return response.text;

  } catch (error) {
    console.error("Erreur lors de l'appel à l'API Gemini:", error);
    if (error instanceof Error) {
        throw new Error(`Erreur de l'API Gemini : ${error.message}`);
    }
    throw new Error("Une erreur inconnue est survenue lors de la communication avec l'API Gemini.");
  }
};

import React from 'react';

const Header: React.FC = () => {
  return (
    <header className="bg-white dark:bg-gray-800 shadow-md">
      <div className="max-w-7xl mx-auto py-4 px-4 sm:px-6 lg:px-8">
        <div className="flex items-center space-x-3">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-blue-600 dark:text-blue-400" viewBox="0 0 20 20" fill="currentColor">
            <path d="M9 2a1 1 0 000 2h2a1 1 0 100-2H9z" />
            <path fillRule="evenodd" d="M4 5a2 2 0 012-2 3 3 0 003 3h2a3 3 0 003-3 2 2 0 012 2v11a2 2 0 01-2 2H6a2 2 0 01-2-2V5zm3 4a1 1 0 000 2h.01a1 1 0 100-2H7zm3 0a1 1 0 000 2h3a1 1 0 100-2h-3zm-3 4a1 1 0 100 2h.01a1 1 0 100-2H7zm3 0a1 1 0 100 2h3a1 1 0 100-2h-3z" clipRule="evenodd" />
          </svg>
          <h1 className="text-2xl font-bold text-gray-800 dark:text-white">
            Générateur de Rapport Académique
          </h1>
        </div>
      </div>
    </header>
  );
};

export default Header;

import React from 'react';

interface PromptInputProps {
  prompt: string;
  setPrompt: (prompt: string) => void;
  onGenerate: () => void;
  isLoading: boolean;
}

const PromptInput: React.FC<PromptInputProps> = ({ prompt, setPrompt, onGenerate, isLoading }) => {
  return (
    <div className="bg-white dark:bg-gray-800 rounded-lg shadow-lg p-6 flex flex-col h-full">
      <label htmlFor="prompt" className="text-lg font-semibold text-gray-800 dark:text-white mb-2">
        Instructions pour le Rapport
      </label>
      <p className="text-sm text-gray-500 dark:text-gray-400 mb-4">
        Collez ou modifiez les consignes ci-dessous pour générer le rapport. Le modèle est pré-configuré pour suivre la structure demandée.
      </p>
      <textarea
        id="prompt"
        value={prompt}
        onChange={(e) => setPrompt(e.target.value)}
        className="flex-grow w-full p-3 border border-gray-300 dark:border-gray-600 rounded-md bg-gray-50 dark:bg-gray-700 text-gray-900 dark:text-gray-200 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-shadow duration-200 resize-none font-mono text-sm"
        placeholder="Décrivez en détail le rapport que vous souhaitez générer..."
        rows={20}
      />
      <button
        onClick={onGenerate}
        disabled={isLoading}
        className="mt-4 w-full inline-flex justify-center items-center px-6 py-3 border border-transparent text-base font-medium rounded-md shadow-sm text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 disabled:bg-blue-300 dark:disabled:bg-blue-800 disabled:cursor-not-allowed transition-colors"
      >
        {isLoading ? (
          <>
            <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
            </svg>
            Génération en cours...
          </>
        ) : (
          'Générer le Rapport'
        )}
      </button>
    </div>
  );
};

export default PromptInput;

import React from 'react';
// Since we cannot use npm packages, we import ReactMarkdown from a CDN via esm.sh
// This works with modern browsers and bundlers that support ES modules.
import ReactMarkdown from 'https://esm.sh/react-markdown@9';
import remarkGfm from 'https://esm.sh/remark-gfm@4';
import Spinner from './Spinner';

interface ReportOutputProps {
  content: string;
  isLoading: boolean;
  error: string | null;
  onDownload: () => void;
}

const ReportOutput: React.FC<ReportOutputProps> = ({ content, isLoading, error, onDownload }) => {
  return (
    <div className="bg-white dark:bg-gray-800 rounded-lg shadow-lg p-6 flex flex-col h-full">
        <div className="flex justify-between items-center mb-4">
            <h2 className="text-lg font-semibold text-gray-800 dark:text-white">
            Aperçu du Rapport
            </h2>
            {content && !isLoading && (
            <button
                onClick={onDownload}
                className="inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-green-600 hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500"
            >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 mr-2" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M3 17a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1zm3.293-7.707a1 1 0 011.414 0L9 10.586V3a1 1 0 112 0v7.586l1.293-1.293a1 1 0 111.414 1.414l-3 3a1 1 0 01-1.414 0l-3-3a1 1 0 010-1.414z" clipRule="evenodd" />
                </svg>
                Télécharger (.doc)
            </button>
            )}
      </div>

      <div className="flex-grow w-full border border-gray-200 dark:border-gray-700 rounded-md overflow-y-auto p-4 bg-gray-50 dark:bg-gray-900/50 prose dark:prose-invert max-w-none prose-h1:text-xl prose-h2:text-lg prose-h3:text-base prose-p:text-sm">
        {isLoading && <Spinner />}
        {error && <div className="text-red-500 dark:text-red-400 p-4 bg-red-100 dark:bg-red-900/50 rounded-md">{error}</div>}
        {!isLoading && !error && !content && (
          <div className="text-center text-gray-500 dark:text-gray-400 h-full flex items-center justify-center">
            <p>Le rapport généré apparaîtra ici.</p>
          </div>
        )}
        {content && (
            <div id="report-preview">
                <ReactMarkdown remarkPlugins={[remarkGfm]}>{content}</ReactMarkdown>
            </div>
        )}
      </div>
      {/* Hidden div for DOCX export */}
      <div id="html-source" style={{ display: 'none' }}>
        <ReactMarkdown remarkPlugins={[remarkGfm]}>{content}</ReactMarkdown>
      </div>
    </div>
  );
};

export default ReportOutput;

import React from 'react';

const Spinner: React.FC = () => {
  return (
    <div className="flex flex-col items-center justify-center h-full">
      <div className="w-12 h-12 rounded-full animate-spin border-4 border-solid border-blue-500 border-t-transparent"></div>
      <p className="mt-4 text-gray-600 dark:text-gray-300">Génération du rapport en cours...</p>
      <p className="text-sm text-gray-500 dark:text-gray-400">Cela peut prendre quelques instants.</p>
    </div>
  );
};

export default Spinner;
